settings.default:
/* Base button styles using CSS variables (set by JavaScript) */
/* Loading state for user interactions */
.swym-loading .swym-button-content button,
.swym-loading .swym-button-content [role="button"],
.swym-loading .swym-button-content .btn,
.swym-loading .swym-button-content a {
  opacity: 0.6;
  cursor: not-allowed;
  pointer-events: none;
}
.swym-button-content > button,
.swym-button-content > [role="button"],
.swym-button-content > span,
.swym-button-content > a {
  color: var(--swym-theme-layout-button-color-text-primary, #fff);
  background: var(--swym-theme-layout-button-color-bg-primary, #000);
  border-color: var(--swym-theme-layout-button-border-color-primary, #000);
  border-width: var(--swym-theme-layout-button-border-width-primary, 1px);
  border-style: var(--swym-theme-layout-button-border-style-primary, solid);
  border-radius: var(--swym-theme-layout-button-border-radius-primary, 0px);
  font-family: inherit;
  padding: 12px 16px;
  font-size: 14px;
  font-weight: normal;
  display: flex;
  justify-content: center;
  align-items: center;
  cursor: pointer;
  transition: all 0.2s ease;
  text-align: center;
  pointer-events: auto;
  min-height: 45px;
  width: 100%;
  letter-spacing: normal;
}

/* Focus styles for accessibility */
.swym-button-content button:focus-visible,
.swym-button-content [role="button"]:focus-visible,
.swym-button-content .btn:focus-visible,
.swym-button-content a:focus-visible {
  outline: 2px solid currentColor;
  outline-offset: 2px;
}
/* Disabled state styles */
.swym-button-content button:disabled,
.swym-button-content [role="button"][aria-disabled="true"],
.swym-button-content .btn:disabled,
.swym-button-content a[aria-disabled="true"] {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}
/* Product image position styling (top-left default) */
.swym-atw-btn-wrapper-for-img.swym-btn-position-product-img {
  position: absolute;
  top: 10px;
  left: 10px;
  z-index: 10;
  width: fit-content!important;
}
.swym-custom-pdp-button.swym-btn-position-product-title {
  width: fit-content;
}
.swym-button-content.swym-btn-custom-position {
  margin-top: 8px;
}
.swym-button-content button.swym-icon-text svg {
  margin-right: 5px;
}
/* ACCESSIBILITY IMPROVEMENTS */
@media (prefers-reduced-motion: reduce) {
  .swym-button-content,
  .swym-button-content button,
  .swym-button-content [role="button"],
  .swym-button-content .btn,
  .swym-button-content a {
    transition: none;
    animation: none;
  }
  .swym-button-content.swym-initialized button:hover,
  .swym-button-content.swym-initialized [role="button"]:hover,
  .swym-button-content.swym-initialized .btn:hover,
  .swym-button-content.swym-initialized a:hover {
    transform: none;
  }
}
/* HIGH CONTRAST MODE SUPPORT */
@media (prefers-contrast: high) {
  .swym-atw-btn-wrapper-for-img .swym-button-content button,
  .swym-atw-btn-wrapper-for-img .swym-button-content [role="button"],
  .swym-atw-btn-wrapper-for-img .swym-button-content .btn,
  .swym-atw-btn-wrapper-for-img .swym-button-content a {
    border: 2px solid;
    background: #fff;
  }
}

.swym-advanced-wishlist-collections-container {
  position: absolute;
  top: 0;
  left: 0;
  padding: 10px;
  z-index: 5;
  cursor: pointer;
  width: 60px;
  height: 40px;
}

.swym-advanced-wishlist-collections,
.swym-advanced-wishlist-collections svg {
  cursor: pointer;
  background: unset;
  border: none;
  box-shadow: none;
  display: flex;
  align-items: center;
  flex-direction: row-reverse;
  gap: 5px;
  color: currentColor;
  min-width: 24px;
  min-height: 24px;
}

button.swym-advanced-wishlist-collections:hover {
  background: none;
  border: none;
  box-shadow: none;
}

.swym-advanced-wishlist-collections svg path {
  stroke: currentColor;
}

.swym-advanced-wishlist-collections .swym-advanced-wishlist-collections-social-count {
  font-size: 14px;
  font-weight: 500;
  color: currentColor;
}

.swym-sr-only {
  clip: rect(0 0 0 0);
  clip-path: inset(50%);
  height: 1px;
  width: 1px;
  overflow: hidden;
  white-space: nowrap;
  position: absolute;
}

/* Circular background for icon */
.swym-circular-bg button.swym-advanced-wishlist-collections {
  position: relative;
  flex-direction: unset;
  padding: 0;
  background: none;
  border: none;
  box-shadow: none;
}

.swym-circular-bg .swym-icon-bg {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

/*for active*/
/* Make button position: relative so badge positions correctly */
.swym-circular-bg .swym-advanced-wishlist-collections {
  position: relative;
}

/* Badge styling when social count is active */
.swym-circular-bg .swym-social-count-active {
  position: absolute;
  top: -6px;
  right: -6px;
  background: #000000;
  color: #FFFFFF;
  border-radius: 50%;
  width: 16px;
  height: 16px;
  font-size: 10px;
  font-weight: 600;
  line-height: 16px;
  text-align: center;
  z-index: 1;
}
